import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1. Search for Trump tariffs markets to find the top one
  const searchResult = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: "Trump tariffs",
      status: "open",
      limit: 1
    }
  });

  const markets = searchResult.results || [];
  if (markets.length === 0) {
    return { error: "No active Trump tariffs markets found." };
  }

  const topMarket = markets[0];
  const ticker = topMarket.ticker;

  // 2. Get sentiment and price trend analysis for the last 24 hours
  const sentimentResult = await callMcpSkill({
    toolId,
    toolName: "analyze_market_sentiment",
    args: {
      ticker: ticker,
      periodHours: 24
    }
  });

  // 3. Get recent trades to provide context on current activity
  const tradesResult = await callMcpSkill({
    toolId,
    toolName: "get_market_trades",
    args: {
      ticker: ticker,
      limit: 5
    }
  });

  return {
    marketTitle: topMarket.title,
    marketUrl: topMarket.url,
    ticker: ticker,
    sentiment: sentimentResult,
    recentActivity: tradesResult.summary,
    recentTrades: tradesResult.trades
  };
}

